// n8n Code node (JS)
// Entrada soportada:
//  a) items[0].json = [ { id, sku_base, categoria, descripcion }, ... ]
//  b) items[0].json.data = [ ... ]
//  c) items = [ { json: { id, sku_base, categoria, descripcion } }, ... ]
//
// Salida:
//  [{ json: { concept: "promocionesejemplo", value: "canal:promocion1, canal:promocion2, ..." } }]

function getArrayFromItems(items) {
  if (Array.isArray(items?.[0]?.json)) return items[0].json;
  if (Array.isArray(items?.[0]?.json?.data)) return items[0].json.data;
  return items.map(it => it.json);
}

function sampleN(arr, n) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a.slice(0, Math.min(n, a.length));
}

const data = getArrayFromItems(items);

// Concatena "canal" con "promocion", elimina vacíos y dedup (case-insensitive)
const combinedItems = data
  .map(o => {
    const canal = (o?.canal ?? '').toString().trim();
    const promocion = (o?.promocion ?? '').toString().trim();

    // Solo incluir si ambos campos tienen valor
    if (canal && promocion) {
      return `${canal}:${promocion}`;
    }
    return null;
  })
  .filter(Boolean);

const uniqueItems = [...new Map(combinedItems.map(item => [item.toLowerCase(), item])).values()];

const selected = sampleN(uniqueItems, 3);
const value = selected.join(', ');

return [{ json: { concept: 'promocionesejemplo', value } }];

// n8n Code node (JS)
// Entrada soportada:
//  a) items[0].json = [ { id, sku_base, categoria, descripcion }, ... ]
//  b) items[0].json.data = [ ... ]
//  c) items = [ { json: { id, sku_base, categoria, descripcion } }, ... ]
//
// Salida:
//  [{ json: { concept: "categorias_menu", value: "Cat A, Cat B, Cat C" } }]

function getArrayFromItems(items) {
  if (Array.isArray(items?.[0]?.json)) return items[0].json;
  if (Array.isArray(items?.[0]?.json?.data)) return items[0].json.data;
  return items.map(it => it.json);
}

function sampleN(arr, n) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a.slice(0, Math.min(n, a.length));
}

const data = getArrayFromItems(items);

// Normaliza, elimina vacíos y dedup (case-insensitive) manteniendo el primer casing visto
const cats = data
  .map(o => (o?.categoria ?? '').toString().trim())
  .filter(Boolean);

const uniqueCats = [...new Map(cats.map(c => [c.toLowerCase(), c])).values()];

const selected = sampleN(uniqueCats, 3);
const value = selected.join(', ');

return [{ json: { concept: 'categorias_menu', value } }];

// n8n Code node (JS)
// Tropicalizado a **Salón** (no toma pedidos ni hace seguimiento).
// Objetivo: saludar y orientar a: reservaciones, menú, recomendaciones y promociones.

// --- 1. OBTENER DATOS DE LA SUCURSAL ---
// Extraemos el nombre de la sucursal desde el nodo "Get Data Sucursal"
let sucursalNombre = '';
try {
  const dataSucursal = $('Get Data Sucursal').first().json;
  sucursalNombre = (dataSucursal.nombre || '').toString().trim();
} catch (error) {
  // Si el nodo no existe/no se ejecutó, seguimos sin sucursal (no rompemos el flujo)
  sucursalNombre = '';
}

// --- 2. OBTENER DATOS DE LA MARCA (Nodo "Code") ---
// Contexto del negocio (branding + categorías)
const ctx = $('Code').first().json;

const marcacorta = (ctx.marcacorta ?? 'nuestro restaurante').toString().trim();
const gastronomia = (ctx.gastronomia ?? 'deliciosa').toString().trim();

// Procesar categorías del menú (para usarlo en copy sin alucinar cosas)
let categorias_menu = ctx.categorias_menu;
if (Array.isArray(categorias_menu)) {
  categorias_menu = categorias_menu.filter(Boolean).join(', ');
} else if (categorias_menu == null) {
