// --- 4. UTILIDADES ---
// Selección aleatoria sin repetición
function sampleN(arr, n) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a.slice(0, Math.min(n, a.length));
}

// Reemplazo de placeholders {marcacorta}, {sucursal}, etc.
function fillPlaceholders(str, vars) {
  return str.replace(/\{(\w+)\}/g, (_, k) => {
    const v = vars[k];

    // Si sucursal viene vacía, no insertamos nada (y evitamos "doble espacio")
    if (k === 'sucursal') {
      if (!v || String(v).trim() === '') return '';
      // Si hay sucursal, la pegamos con un separador natural (ej: " Osaki - Calle 47")
      const s = String(v).trim();
      // si ya viene con guión/paréntesis, no metemos otro
      if (/^[-–—(]/.test(s)) return ` ${s}`;
      return ` - ${s}`;
    }

    return v === undefined || v === null ? `{${k}}` : String(v);
  });
}

// --- 5. PROCESAMIENTO FINAL ---
// Entregamos 3 variantes para rotación (evitar patrón)
const seleccionadas = sampleN(respuestas, 3).map(s =>
  fillPlaceholders(s, {
    marcacorta,
    gastronomia,
    categorias_menu,
    sucursal: sucursalNombre
  })
);

// Limpieza final: colapsa espacios, recorta extremos, y une en multimensaje
const outputValue = seleccionadas.map(s => s.replace(/\s+/g, ' ').trim()).join('\n');

return [
  {
    json: {
      concept: 'ejemplosbienvenida_salon',
      value: outputValue
    }
  }
];

// n8n Code node (JavaScript)
// Convierte el arreglo Aggregate.data[*].message{type, content} en un objeto plano:
// { "Humano_1": "...", "IA_1": "...", "Humano_2": "...", "IA_2": "..." }

const items = $input.all();

// Limpia el texto: recorta, colapsa espacios y, si viene el bloque largo,
// extrae lo que sigue a "Mensaje de Texto o Descripción:"
function cleanText(s) {
  if (!s) return '';
  let t = String(s);

  const marker = 'Mensaje de Texto o Descripción';
  const idx = t.toLowerCase().indexOf(marker.toLowerCase());
  if (idx !== -1) {
    t = t.slice(idx + marker.length);
  }

  // Quita separadores iniciales y colapsa espacios/nuevas líneas
  t = t.replace(/^[\s:.-]+/, '').replace(/\s+/g, ' ').trim();
  return t;
}

// Extrae mensajes desde varias formas posibles
const records = [];
for (const it of items) {
  const j = it.json || {};

  // Si viene como { data: [...] } úsalo; si no, intenta interpretar el propio objeto
  const arr = Array.isArray(j.data) ? j.data : (Array.isArray(j) ? j : (j.data ? [j.data] : [j]));

  for (const row of arr) {
    const msg = row?.message || row;
    const type = (msg?.type || msg?.role || '').toLowerCase();
    const content = msg?.content ?? msg?.text ?? '';

    if (!type || !content) continue;

    const role = (type === 'human' || type === 'user') ? 'Humano' : 'IA';
    records.push({ role, text: cleanText(content) });
  }
}

// Construye objeto plano con claves enumeradas
const out = {};
let h = 1, a = 1;
for (const r of records) {
  if (r.role === 'Humano') out[`Humano_${h++}`] = r.text;
  else out[`IA_${a++}`] = r.text;
}

return [{ json: out }];

// Code (JavaScript) ANTES del Summarization Chain
// Convierte Humano_*/IA_* en un solo bloque de texto ordenado
const it = $input.first().json;
const lines = Object.entries(it)
  .filter(([k]) => /^(Humano|IA)_(\d+)$/i.test(k))
  .sort((a,b) => parseInt(a[0].match(/\d+/)[0],10) - parseInt(b[0].match(/\d+/)[0],10))
  .map(([k,v]) => `${k.startsWith('Humano') ? 'Humano' : 'IA'}: ${String(v).trim()}`);

return [{ json: { text: lines.join('\n') } }];

