// n8n Code Node (JavaScript)
// Fuentes:
// - Nodo "Code": info del negocio (marca, agente, contactos, slogan, etc.)
// - Nodo "Normaliza1": campo "VIP" con formato tipo "Sí:9"

function safeJsonParse(maybeJson, fallback) {
  try {
    if (typeof maybeJson !== "string") return maybeJson ?? fallback;
    const s = maybeJson.trim();
    if (!s) return fallback;
    return JSON.parse(s);
  } catch (e) {
    return fallback;
  }
}

function toTitleCase(s) {
  if (!s || typeof s !== "string") return s;
  return s
    .toLowerCase()
    .split(" ")
    .filter(Boolean)
    .map(w => w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ");
}

function pickFirst(arr, predicate) {
  if (!Array.isArray(arr)) return null;
  if (!predicate) return arr[0] ?? null;
  return arr.find(predicate) ?? arr[0] ?? null;
}

function extractNumPersonasFromVIP(vipRaw) {
  // vipRaw esperado: "Sí:9" | "Sí: 9" | "No" | "Si:12" | "Sí:VIP"
  if (vipRaw == null) return null;
  const s = String(vipRaw).trim();

  // Busca el primer entero en el string
  const m = s.match(/(\d{1,3})/);
  if (m) return parseInt(m[1], 10);

  return null;
}

// --------------------
// 1) Obtener inputs
// --------------------
const negocio = $("Code").first()?.json ?? {};
const normaliza = $("Normaliza1").first()?.json ?? {};

// --------------------
// 2) Variables negocio
// --------------------
const nombreNegocio = negocio.nombre || negocio.Nombre || "Osaki Sushi";
const marca = negocio.marcacorta || negocio.MarcaCorta || "Osaki";
const slogan = negocio.slogan || negocio.Slogan || "Pedí un deseo & compartilo";
const emojis = negocio.emojis || "🍣🥢🍶";
const nombreAgente = negocio.nombreagente || negocio.NombreAgente || "Emi";
const generoAgente = negocio.generoagente || negocio.GeneroAgente || "Femenino";

const contactosWhatsapp = safeJsonParse(negocio.whatsapp || negocio.Whatsapp, []);
const contactosTelefono = safeJsonParse(negocio.telefono || negocio.Telefono, []);
const direcciones = safeJsonParse(negocio.direccion || negocio.Direccion, []);
const horarios = safeJsonParse(negocio.horariosatencion || negocio.HorariosAtencion, []);

const contactoReservasDirecto =
  (negocio.contactoreservas && String(negocio.contactoreservas).trim()) ||
  (negocio.ContactoReservas && String(negocio.ContactoReservas).trim()) ||
  null;

const urlReservas =
  negocio.urlreservas || negocio.URLReservas || "WhatsApp por sucursal (ver Whatsapp)";

const menuSalon = negocio.menusalon || negocio.MenuSalon || null;

const whatsappReservas =
  contactoReservasDirecto
    ? `+54 9 ${contactoReservasDirecto.replace(/[^\d]/g, "")}`
    : (pickFirst(contactosWhatsapp)?.whatsapp || pickFirst(contactosWhatsapp)?.Whatsapp || null);

const telGeneral =
  pickFirst(contactosTelefono)?.telefono || pickFirst(contactosTelefono)?.Telefono || null;

const direccionPrincipal =
  (pickFirst(direcciones)?.principal && pickFirst(direcciones)?.direccion)
    ? `${pickFirst(direcciones).principal}: ${pickFirst(direcciones).direccion}`
    : (pickFirst(direcciones)?.direccion || null);

const horarioPrincipal =
  pickFirst(horarios)?.horario || pickFirst(horarios)?.Horario || null;

// --------------------
// 3) Número de personas
// --------------------
const vipRaw = normaliza.VIP ?? normaliza.vip ?? "";
const numPersonas = extractNumPersonasFromVIP(vipRaw);

// Regla de negocio: solo este flujo para >6
const esGrupoGrande = (Number.isFinite(numPersonas) && numPersonas > 6);

// --------------------
