// --- FUNCIÓN DE LIMPIEZA ROBUSTA ---
function cleanBotResponse(text) {
    if (typeof text !== 'string') return '';

    let processed = text.trim();
    let keepCleaning = true;
    let loopCount = 0;

    // 1. ELIMINACIÓN DE BLOQUES TIPO TOOL (Iterativo)
    while (keepCleaning && loopCount < 10) { // Max 10 iteraciones por seguridad
        loopCount++;

        // Buscamos si empieza con un bloque de herramienta típico
        // Puede empezar con [Used, con ; Tool, o simplemente con [
        const startMarker = processed.match(/^(\[|;?\s*Tool:|;?\s*\[)/);

        if (startMarker) {
            // Buscamos el primer corchete de apertura real para iniciar el conteo
            const openBracketIndex = processed.indexOf('[');

            if (openBracketIndex !== -1 && openBracketIndex < 5) { // Debe estar al inicio
                let depth = 0;
                let inDoubleQuote = false;
                let inSingleQuote = false;
                let endIndex = -1;

                // Recorremos desde el corchete de apertura
                for (let i = openBracketIndex; i < processed.length; i++) {
                    const char = processed[i];
                    const prevChar = i > 0 ? processed[i - 1] : null;

                    // Lógica de comillas para no contar corchetes internos del texto
                    if (char === '"' && prevChar !== '\\' && !inSingleQuote) inDoubleQuote = !inDoubleQuote;
                    else if (char === "'" && prevChar !== '\\' && !inDoubleQuote) inSingleQuote = !inSingleQuote;

                    if (!inDoubleQuote && !inSingleQuote) {
                        if (char === '[') depth++;
                        else if (char === ']') {
                            depth--;
                            if (depth === 0) {
                                endIndex = i;
                                break;
                            }
                        }
                    }
                }

                if (endIndex !== -1) {
                    // Cortamos el bloque detectado
                    processed = processed.substring(endIndex + 1).trim();
                } else {
                    // Si el JSON está roto (no cierra), forzamos salida para evitar bucle infinito
                    // y limpiamos caracteres raros del inicio manualmente
                    keepCleaning = false;
                }
            } else {
                // Si detecta "Tool:" pero no hay corchetes, limpia con Regex simple
                processed = processed.replace(/^;?\s*Tool:[^\[]+/, '').trim();
            }
        } else {
            // Si ya no empieza con [ o Tool, terminamos el bucle principal
            keepCleaning = false;
        }
    }

    // 2. FASE DE SANITIZACIÓN FINAL (Aquí corregimos el "]" sobrante)
    // Elimina cualquier corchete de cierre ']', punto y coma ';', coma ',' o espacios 
    // que hayan quedado "huérfanos" al principio del string.
    processed = processed.replace(/^[\s\];,\n]+/, '');

    return processed;
}

// --- EJECUCIÓN ---

let processedOutput = cleanBotResponse(output);

// 3. LIMPIEZA DE FORMATO MARKDOWN
processedOutput = processedOutput.replace(/\*\*/g, '*');
processedOutput = processedOutput.trim();

// 4. VERIFICACIÓN FINAL
if (processedOutput.length === 0) {
    processedOutput = fallbackMessage;
}

return [
  {
    json: {
      ...restOfInput,      
      output: processedOutput, 
      randomNumber          
    }
  }
];

