    const fechaLarga = d.toLocaleDateString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires', weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });    
    return `${fechaHora}`;    
    })()

    }}

parameters.jsCode:
// n8n Code Node (JavaScript)
// Fuentes:
// - Nodo "Code": info del negocio (marca, agente, contactos, slogan, etc.)
// - Nodo "Normaliza1": campo "VIP" con formato tipo "Sí:9"

function safeJsonParse(maybeJson, fallback) {
  try {
    if (typeof maybeJson !== "string") return maybeJson ?? fallback;
    const s = maybeJson.trim();
    if (!s) return fallback;
    return JSON.parse(s);
  } catch (e) {
    return fallback;
  }
}

function toTitleCase(s) {
  if (!s || typeof s !== "string") return s;
  return s
    .toLowerCase()
    .split(" ")
    .filter(Boolean)
    .map(w => w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ");
}

function pickFirst(arr, predicate) {
  if (!Array.isArray(arr)) return null;
  if (!predicate) return arr[0] ?? null;
  return arr.find(predicate) ?? arr[0] ?? null;
}

function extractNumPersonasFromVIP(vipRaw) {
  // vipRaw esperado: "Sí:9" | "Sí: 9" | "No" | "Si:12" | "Sí:VIP"
  if (vipRaw == null) return null;
  const s = String(vipRaw).trim();

  // Busca el primer entero en el string
  const m = s.match(/(\d{1,3})/);
  if (m) return parseInt(m[1], 10);

  return null;
}

// --------------------
// 1) Obtener inputs
// --------------------
const negocio = $("Code").first()?.json ?? {};
const normaliza = $("Normaliza1").first()?.json ?? {};

// --------------------
// 2) Variables negocio
// --------------------
const nombreNegocio = negocio.nombre || negocio.Nombre || "Osaki Sushi";
const marca = negocio.marcacorta || negocio.MarcaCorta || "Osaki";
const slogan = negocio.slogan || negocio.Slogan || "Pedí un deseo & compartilo";
const emojis = negocio.emojis || "🍣🥢🍶";
const nombreAgente = negocio.nombreagente || negocio.NombreAgente || "Emi";
const generoAgente = negocio.generoagente || negocio.GeneroAgente || "Femenino";

const contactosWhatsapp = safeJsonParse(negocio.whatsapp || negocio.Whatsapp, []);
const contactosTelefono = safeJsonParse(negocio.telefono || negocio.Telefono, []);
const direcciones = safeJsonParse(negocio.direccion || negocio.Direccion, []);
const horarios = safeJsonParse(negocio.horariosatencion || negocio.HorariosAtencion, []);

const contactoReservasDirecto =
  (negocio.contactoreservas && String(negocio.contactoreservas).trim()) ||
  (negocio.ContactoReservas && String(negocio.ContactoReservas).trim()) ||
  null;

const urlReservas =
  negocio.urlreservas || negocio.URLReservas || "WhatsApp por sucursal (ver Whatsapp)";

const menuSalon = negocio.menusalon || negocio.MenuSalon || null;

const whatsappReservas =
  contactoReservasDirecto
    ? `+54 9 ${contactoReservasDirecto.replace(/[^\d]/g, "")}`
    : (pickFirst(contactosWhatsapp)?.whatsapp || pickFirst(contactosWhatsapp)?.Whatsapp || null);

const telGeneral =
  pickFirst(contactosTelefono)?.telefono || pickFirst(contactosTelefono)?.Telefono || null;

const direccionPrincipal =
  (pickFirst(direcciones)?.principal && pickFirst(direcciones)?.direccion)
    ? `${pickFirst(direcciones).principal}: ${pickFirst(direcciones).direccion}`
    : (pickFirst(direcciones)?.direccion || null);

const horarioPrincipal =
  pickFirst(horarios)?.horario || pickFirst(horarios)?.Horario || null;

// --------------------
// 3) Número de personas
// --------------------
const vipRaw = normaliza.VIP ?? normaliza.vip ?? "";
const numPersonas = extractNumPersonasFromVIP(vipRaw);

// Regla de negocio: solo este flujo para >6
const esGrupoGrande = (Number.isFinite(numPersonas) && numPersonas > 6);

// --------------------
// 4) Helper texto
// --------------------
const agenteFirma = `*${nombreAgente}* (${marca})`;
const infoContacto = telGeneral ? `☎️ Teléfono: *${telGeneral}*` : null;

const infoExtra = [
  direccionPrincipal ? `📍 ${direccionPrincipal}` : null,
  horarioPrincipal ? `🕒 Horarios: ${horarioPrincipal}` : null,
  menuSalon ? `📄 Menú salón: ${menuSalon}` : null,
].filter(Boolean).join("\n");

// --------------------
// 5) 40 plantillas largas
// --------------------
const n = Number.isFinite(numPersonas) ? numPersonas : "varias";
const grupoTxt = `*${n} personas*`;

const variantes = [
  // 1-10: ENFOQUE EN EXPERIENCIA Y COORDINACIÓN
  `Como tu reservación es para ${grupoTxt}, la manejamos con coordinación personalizada para asegurar que el grupo quede cómodo y el servicio fluya excelente ✨.\n\n*En unos instantes alguien del equipo te escribirá por aquí* para confirmar *día, horario y nombre*. Así evitamos sobreprometer y te damos una experiencia extraordinaria.`,

  `${emojis} Para reservas de ${grupoTxt} no hacemos “confirmación automática” porque cambia mucho según el turno.\n\n*Danos un momento, ya te escribe una persona para auxiliarte* y cerrar *fecha/hora* 🗓️. Si querés, también pueden definir el estilo: algo tranquilo o más de festejo.\n\n`,

  `Recibí tu solicitud para ${grupoTxt} y la derivé al equipo porque es un grupo grande.\n\nLo hacemos así por un motivo simple: preferimos confirmarte correctamente antes que decirte “sí” y después ajustar sobre la marcha 📉.\n\n*En breve un integrante del equipo entrará al chat* para ayudarte.`,

  `${emojis} Para una mesa de ${grupoTxt}, el equipo te va a escribir porque necesitamos asegurar *comodidad + logística*.\n\n*Quedate en línea, en unos instantes alguien te contacta* para resolver en 1 minuto:\n- día y horario\n- nombre\n\n`,

  `Las reservas para ${grupoTxt} se coordinan manualmente porque ahí se gana o se pierde la experiencia: una mesa bien armada hace que todo sea extraordinario.\n\n*Ya le avisé a mis compañeros; en breve te contacta alguien del equipo* para confirmar disponibilidad y dejarlo cerrado ✅.`,

  `Para ${grupoTxt} lo tratamos como “grupo grande”: lo toma el equipo para asegurar que la mesa quede cómoda y que el ritmo del servicio acompañe 🍷.\n\n*Danos un momento, ya te escribe una persona* para confirmar *fecha/hora* y la mejor zona.\n\n${infoExtra ? infoExtra : ""}`.trim(),

  `${emojis} Como son ${grupoTxt}, preferimos coordinarlo con una persona del equipo.\n\n¿Por qué? Porque así ajustamos turnos y ubicación sin improvisar. *En unos instantes alguien te escribirá para confirmarte todo*.\n\n`,

  `Ya quedó detectada la reserva para ${grupoTxt}. En este caso *te escribe una persona del equipo para confirmación personalizada* 📲.\n\nTe pido unos minutos; teniendo el *nombre*, *día* y *hora preferida* lo cerramos más rápido cuando te contacten.`,

  `Para ${grupoTxt} hacemos confirmación más personal porque queremos que se sienta ordenado desde el inicio.\n\n*En breve te escriben mis compañeros* para confirmar: *fecha y hora y nombre*. Y si querés, también te recomiendan cómo armar una experiencia para compartir 🍽️.\n\n`,

  `${emojis} Para ${grupoTxt} lo gestiona el equipo para asegurar disponibilidad real.\n\n*Danos un momento, ya entra alguien al chat* para dejarlo confirmado con un solo mensaje final.`,


  // 11-20: ENFOQUE EN LOGÍSTICA Y COMODIDAD
  `Reservar para ${grupoTxt} implica coordinar bien para que no esperen ni queden incómodos.\n\nPor eso *te contacta alguien del equipo en breve*: confirman *día/hora* 📅, sugieren *zona* y listo.\n\n`,

  `Como es una reserva de ${grupoTxt}, el sistema no la “cierra solo”: la toma un integrante del equipo 🙋‍♂️.\n\n*En unos instantes te escribe una persona* para confirmarte disponibilidad y dejarlo formalizado.`,

  `${emojis} Para ${grupoTxt} aplicamos coordinación asistida porque queremos que la experiencia sea extraordinaria para todos.\n\n*Aguantanos un momento, ya te contacta el equipo* para cerrar *fecha/hora/zona*.\n\n`,

  `Para una mesa de ${grupoTxt} lo maneja el equipo para que no quede nada “a ojo”.\n\n*En breve te escribe un asesor*. Cuando te contacten, si hay más de una opción, te proponen alternativas rápidas (ej: Salón vs VIP).`,

  `Reserva para ${grupoTxt}: perfecto. La confirmación la hace el equipo porque en grupos grandes puede variar según el turno.\n\n*Te pido un instante, ya te contacta una persona* para dejarlo cerrado 👌.\n\n${infoExtra ? infoExtra : ""}`.trim(),

  `${emojis} Para ${grupoTxt} hacemos confirmación manual para garantizar que el grupo quede bien ubicado.\n\n*En unos instantes te escribe alguien del equipo* y lo confirmamos de forma clara.\n\n`,

  `Como son ${grupoTxt}, lo derivé al equipo para coordinación personalizada.\n\nEsto evita el clásico problema: “confirmado” pero después cambios 🚫. *En breve entra un compañero al chat* para confirmarte bien desde el inicio.`,

  `Para una reserva de ${grupoTxt} *te contacta alguien del equipo* para confirmar disponibilidad real.\n\nSi te sirve, decile a la persona que te escriba si prefieren un ambiente más tranquilo o algo más dinámico 🥂.\n\n`,

  `Para ${grupoTxt} el equipo te va a contactar en breve.\n\n*Danos un momento, ya te escribe una persona* para revisar el checklist:\n- día\n- hora\n- zona\n- nombre\n\nY listo, reserva cerrada.`,

  `${emojis} Reserva para ${grupoTxt}: la pasamos a coordinación más personal.\n\n*En unos instantes te escribe alguien* para confirmar y evitarte esperas o cambios a último minuto.\n\n`,


  // 21-30: PROTOCOLOS Y DETALLES
  `Para ${grupoTxt} se activa protocolo “grupo grande”: lo confirma el equipo.\n\n*Te contactan mis compañeros en breve* para definir turno y ubicación, y si hace falta te sugieren la mejor manera de ordenar para compartir 🥘.`,

  `Para reservas de ${grupoTxt} preferimos atención personalizada porque eso reduce fricción: te confirmamos bien una sola vez y queda listo.\n\n*Danos un momento, ya te escribe una persona para auxiliarte* ⏳.\n\n`,

  `${emojis} Como tu reserva es para ${grupoTxt}, *en breve te escribe alguien del equipo*.\n\nLa idea es simple: asegurar que entren cómodos y que el servicio tenga ritmo. Sin promesas “genéricas”.`,

  `Para ${grupoTxt} lo toma el equipo porque se coordina distinto a una mesa chica.\n\n*En unos instantes un integrante del staff te contactará* para confirmar *día/hora* y *nombre*.\n\n`,

  `Reserva para ${grupoTxt}: perfecto.\n\n*En breve te contacta el equipo 💬*. Si ya tenés todos los detalles, decíselo a la persona que te escriba; si no, te ayudamos a elegir para que vivan la mejor experiencia.`,

  `${emojis} Para una mesa de ${grupoTxt}, la confirmación es manual para no fallar en disponibilidad.\n\n*Danos un momento, ya te escribe una persona* y lo dejamos confirmado con claridad.\n\n`,

  `Reservas de ${grupoTxt} se coordinan por equipo.\n\n¿Razón? Mesa, tiempos y ubicación. *Te escriben en breve mis compañeros* para confirmar el turno y dejarlo cerrado 🔐.`,

  `Para ${grupoTxt} te contacta el equipo para asegurar que todo salga prolijo.\n\n*En unos instantes alguien te escribirá*. Cuando lo hagan, si hay alguien con restricciones (sin gluten / veggie 🥦) también lo anotamos.\n\n`,

  `Ya vi la solicitud para ${grupoTxt}. Como es grupo grande, pasa a coordinación especial.\n\n*Te pido unos minutos, ya te contacta una persona* para confirmar disponibilidad real y cerrar la reserva.`,

  `${emojis} Para ${grupoTxt} no automatizamos la confirmación: preferimos coordinarlo bien.\n\n*En breve te escribe alguien del staff* para chequear fecha/hora/zona/nombre.\n\n`,


  // 31-40: CIERRE Y SEGURIDAD
  `Para una reserva de ${grupoTxt} lo toma el equipo para que no haya “sorpresas” 🎁.\n\n*Te contactan en breve*. Si tu idea es festejo, coméntaselo a la persona que te escriba para buscar la zona que más se ajuste.`,

  `Reserva para ${grupoTxt}: la coordinamos manualmente para asegurar comodidad.\n\n*Danos un momento, ya te escribe una persona* para confirmar turno y ubicación.\n\n`,

  `${emojis} Para ${grupoTxt} el equipo te va a contactar en breve.\n\nEsto nos permite confirmar disponibilidad real y dejar la reserva cerrada sin vueltas. *Ya entra alguien al chat* para ayudarte.`,

  `Como son ${grupoTxt}, lo toma el equipo para coordinarlo bien.\n\n*En unos instantes te contactará un asesor* para confirmar *día/hora* y la mejor zona ✨.\n\n`,

  `Para ${grupoTxt} hacemos confirmación personalizada porque queremos una experiencia ordenada.\n\n*En breve te contactan mis compañeros* y lo cerramos 🤝.`,

  `${emojis} Reserva para ${grupoTxt}: perfecto.\n\n*Te escribe alguien del equipo en breve* para confirmación personalizada y dejarlo formalizado.\n\n${infoExtra ? infoExtra : ""}`.trim(),

  `Para ${grupoTxt} lo coordina el equipo.\n\n*Danos un momento, ya te escribe una persona*. Si ya tenés todos los datos bien definidos, cuando te escriban lo confirmamos y listo ✅.\n\n`,

  `Para una mesa de ${grupoTxt}, la confirmación se hace con el equipo para asegurar disponibilidad.\n\n*En unos instantes alguien del staff te escribirá* para ayudarte.`,

  `Reserva para ${grupoTxt} detectada como grupo grande.\n\n*En breve te contacta el equipo* para cerrar *fecha/hora/zona/nombre* y dejarlo confirmado en una sola charla final 🏁.\n\n`,

  `${emojis} Para ${grupoTxt} te contacta el equipo para coordinarlo bien.\n\nAsí garantizamos mesa cómoda y tiempos razonables. *Quedate atenta/o, ya te escribe una persona*.`
];

// --------------------
// 6) Selección aleatoria
// --------------------
const pool = Array.isArray(variantes) && variantes.length ? variantes : [`Hola, soy ${agenteFirma}. Te contacta el equipo en breve.`];
const mensaje = pool[Math.floor(Math.random() * pool.length)];

// --------------------
// 7) Output
// --------------------
return [
  {
    json: {
      // Debug / auditoría
      marca,
      nombre_negocio: nombreNegocio,
      agente: nombreAgente,
      vip_raw: vipRaw,
      num_personas: numPersonas,
      es_grupo_grande: esGrupoGrande,

      // Mensaje final
      output: mensaje,

      timestamp: new Date().toISOString(),
    },
  },
];

// 1. CONFIGURACIÓN DE LÍMITES FIJOS
const CAPACIDAD_SALON = 12; 
const CAPACIDAD_BARRA = 16; 
const CAPACIDAD_VIP = 5; 

// 2. OBTENER LA SOLICITUD DEL CLIENTE
let solicitud;
try {
  solicitud = $('Data Filter').first().json; 
} catch (error) {
  solicitud = { mesas_sugeridas: 0, num_personas: 0 };
}

const reqMesas = Number(solicitud.mesas_sugeridas) || 0;
const reqPersonas = Number(solicitud.num_personas) || 0;

// 3. AGRUPAR DATOS POR FECHA
const filasDB = $input.all().map(item => item.json);
const ocupacionPorFecha = {};

for (const fila of filasDB) {
  const fechaKey = fila.fecha.split('T')[0]; 

  if (!ocupacionPorFecha[fechaKey]) {
    ocupacionPorFecha[fechaKey] = { salon: 0, barra: 0, vip: 0 };
  }

  const zona = (fila.zona || '').toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const ocupacionMesas = Number(fila.num_mesas) || 0;
  const ocupacionPersonas = Number(fila.num_personas) || 0;

  if (zona.includes('salon')) {
    ocupacionPorFecha[fechaKey].salon += ocupacionMesas;
  } else if (zona.includes('barra')) {
    ocupacionPorFecha[fechaKey].barra += ocupacionPersonas;
  } else if (zona.includes('vip')) {
    ocupacionPorFecha[fechaKey].vip += ocupacionMesas;
  }
}

// 4. GENERAR LISTA Y CAPTURAR EL VALOR "PROXIMO"
const fechasOrdenadas = Object.keys(ocupacionPorFecha).sort();
let textoProximo = ""; // Variable para guardar el string corto del primer día

const listaMensajes = fechasOrdenadas.map((fecha, index) => {
  const dia = ocupacionPorFecha[fecha];

  // A. Calcular espacios libres
  const libresSalon = Math.max(0, CAPACIDAD_SALON - dia.salon);
  const libresBarra = Math.max(0, CAPACIDAD_BARRA - dia.barra);

  // B. Evaluar disponibilidad
  const cabeEnSalon = reqMesas > 0 ? reqMesas <= libresSalon : libresSalon > 0;
  const cabeEnBarra = reqPersonas > 0 ? reqPersonas <= libresBarra : libresBarra > 0;

  // C. Determinar el texto de Estado
  let textoStatus = "";

  if (cabeEnSalon && cabeEnBarra) {
    textoStatus = "Disponible";
  } else if (cabeEnSalon && !cabeEnBarra) {
    textoStatus = "Disponible solo en Salón"; 
  } else if (!cabeEnSalon && cabeEnBarra) {
    textoStatus = "Disponible solo en Barra"; 
  } else {
    if (libresSalon === 0 && libresBarra === 0) {
      textoStatus = "Agotado";
    } else {
      textoStatus = "Capacidad insuficiente";
    }
  }

  // --- NUEVO: Si es la primera fecha (índice 0), guardamos el formato solicitado ---
  if (index === 0) {
    textoProximo = `${fecha} : ${textoStatus}`;
  }
  // ---------------------------------------------------------------------------------

  // D. Retornar el string largo para la lista detallada
  return `${fecha} : ${textoStatus} (Ocupación: Salón ${dia.salon}/${CAPACIDAD_SALON}, Barra ${dia.barra}/${CAPACIDAD_BARRA})`;
});

// 5. RETORNAR EL FORMATO FINAL CON LA LLAVE FIJA "proximo"
return {
  json: {
    "id": "1",  
    "concept": "disponibilidad_sushi_libre",
    "value": listaMensajes,
    "proximo": textoProximo // Aquí va el string "Fecha : Status"
  }
};

